package main

import (
	"context"
	"log"

	"go.mongodb.org/mongo-driver/bson"
	"go.mongodb.org/mongo-driver/mongo"
	"go.mongodb.org/mongo-driver/mongo/options"
)

func queryMongoDB(client *mongo.Client, collection string, filter map[string]interface{}) (*mongo.Cursor, error) {
	coll := client.Database("database").Collection(collection)
	query := bson.D{}
	for key, value := range filter {
		if value == "" {
			continue
		}
		field := bson.E{Key: key, Value: value}
		query = append(query, field)
	}

	ctx := context.Background()
	cur, err := coll.Find(ctx, query)
	return cur, err
}

func main() {
	clientOptions := options.Client().ApplyURI("mongodb://localhost:27017/")
	client, err := mongo.NewClient(clientOptions)
	if err != nil {
		log.Fatal(err)
	}
	err = client.Connect(context.TODO())
	if err != nil {
		log.Fatal(err)
	}
	defer client.Disconnect(context.TODO())

	filter := map[string]interface{}{
		"name": "John",
		"age":  30,
	}

	cur, err := queryMongoDB(client, "users", filter)
	if err != nil {
		log.Fatal(err)
	}
	for cur.Next(context.Background()) {
		var result struct {
			Name string `bson:"name"`
			Age  int    `bson:"age"`
		}
		err := cur.Decode(&result)
		if err != nil {
			log.Fatal(err)
		}
		log.Println(result.Name, result.Age)
	}
	cur.Close(context.Background())
}